#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#define PI 3.1415926535897932
#define A 1103515245
#define C 12345
#define M 2147483647 // INT_MAX

inline double randu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return newValue;
    else
        return newValue + 1;
}

__kernel void likelihood_kernel(__global double* arrayX,
                                __global double* arrayY,
                                __global double* xj,
                                __global double* yj,
                                __global double* CDF,
                                __global int* ind,
                                __global int* objxy,
                                __global double* likelihood,
                                __global uchar* I,
                                __global double* u,
                                __global double* weights,
                                const int Nparticles,
                                const int countOnes,
                                const int max_size,
                                const int k,
                                const int IszY,
                                const int Nfr,
                                __global int* seed,
                                __global double* partial_sums,
                                __local double* local_likelihood) {
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    // Move particles with noise
    double newX = arrayX[x] + 1.0 + 5.0 * randn(seed, x);
    double newY = arrayY[x] + (-2.0) + 2.0 * randn(seed, x);

    xj[x] = newX;
    yj[x] = newY;

    // Compute likelihood
    double sum_likelihood = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = roundDouble(newX) + objxy[y * 2 + 1];
        int indY = roundDouble(newY) + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size)
            idx = 0;
        ind[x * countOnes + y] = idx;
        double val = (double)I[idx];
        sum_likelihood += (pow(val - 100.0, 2) - pow(val - 228.0, 2)) / 50.0;
    }
    likelihood[x] = sum_likelihood / (double)countOnes;

    // Update weight with exp(likelihood)
    weights[x] = weights[x] * exp(likelihood[x]);

    // Store partial sums for reduction
    local_likelihood[get_local_id(0)] = weights[x];
    barrier(CLK_LOCAL_MEM_FENCE);

    // Reduce in local memory
    int local_size = get_local_size(0);
    for (int offset = local_size / 2; offset > 0; offset /= 2) {
        if (get_local_id(0) < offset) {
            local_likelihood[get_local_id(0)] += local_likelihood[get_local_id(0) + offset];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write partial sum of this work-group to partial_sums
    if (get_local_id(0) == 0) {
        partial_sums[get_group_id(0)] = local_likelihood[0];
    }
}

__kernel void sum_kernel(__global double* partial_sums, __global double* weights, const int Nparticles) {
    int gid = get_global_id(0);
    // This kernel can be used for final summation if multiple groups exist
    // For simplicity, assume one group and copy partial sum to weights[0]
    if (gid == 0) {
        double sum = 0.0;
        for (int i = 0; i < Nparticles; i++) {
            sum += weights[i];
        }
        partial_sums[0] = sum;
    }
}

