__kernel void find_index_kernel(__global double* arrayX,
                                __global double* arrayY,
                                __global double* CDF,
                                __global double* u,
                                __global double* xj,
                                __global double* yj,
                                __global double* weights,
                                const int Nparticles) {
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    // Find i such that CDF[i] >= u[j]
    int i = -1;
    for (int idx = 0; idx < Nparticles; idx++) {
        if (CDF[idx] >= u[j]) {
            i = idx;
            break;
        }
    }
    if (i == -1) i = Nparticles - 1;

    xj[j] = arrayX[i];
    yj[j] = arrayY[i];
    weights[j] = 1.0 / (double)Nparticles;
}
